"use client";
import { KeyboardEvent, useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const routes=[["Plan","Set the route boundary."],["Move","Carry work through the route."],["Verify","Record the arrival check."]];
export default function RouteMarkerTabs(){const [active,setActive]=useState(0);const reduced=useReducedMotion();const key=(e:KeyboardEvent<HTMLButtonElement>,i:number)=>{const map:{[key:string]:number}={ArrowRight:(i+1)%3,ArrowLeft:(i+2)%3,Home:0,End:2};if(e.key in map){e.preventDefault();setActive(map[e.key]);}};return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><div role="tablist" aria-label="Route phases" className="relative grid grid-cols-3">{routes.map((route,i)=><button key={route[0]} id={`route-${i}`} role="tab" aria-selected={active===i} aria-controls="route-panel" onKeyDown={e=>key(e,i)} onClick={()=>setActive(i)} className="min-h-11 rounded-xl text-xs font-black text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{route[0]}</button>)}<motion.i aria-hidden className="absolute bottom-0 h-1 w-1/3 rounded-full bg-[#f5e642]" animate={{x:`${active*100}%`}} transition={reduced?{duration:0}:{type:"spring",stiffness:350,damping:27}}/></div><motion.div id="route-panel" role="tabpanel" aria-labelledby={`route-${active}`} key={active} initial={{opacity:0}} animate={{opacity:1}} transition={{duration:reduced?.12:.15}} className="mt-4 rounded-2xl bg-[#f4f5f6] p-4"><strong className="text-[#111]">{routes[active][0]}</strong><p className="mt-1 text-sm text-[#4a4a4f]">{routes[active][1]}</p></motion.div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{routes[active][0]} route phase selected.</p></section>}
